package evm

// ERC-2470 singleton factory defaults.
//
// The runtime bytecode and storage shape are copied from the canonical
// deployment at ERC2470Address. ERC-2470 has no initialized storage.

const (
	ERC2470Address       = "0xce0042B868300000d44A59004Da54A005ffdcf9f"
	ERC2470Bech32Address = "nibi1ecqy9wrgxqqqp4z2tyqymf22qp0lmnulf283ls"
	ERC2470CodeHash      = "0xc4d5542b53a8b779595a20a8ddd60e58a6c49d3c3decc2df83ced1c69c8ca807"
	ERC2470RuntimeCode   = ""
)

// ERC2470GenesisAccount returns the canonical factory as a default EVM
// genesis account. The account has no initialized storage.
func ERC2470GenesisAccount() GenesisAccount {
	return GenesisAccount{
		Address: ERC2470Address,
		Code:    ERC2470RuntimeCode,
		Storage: Storage{},
	}
}
